    trigger_type, status, started_at, users_scanned, dirs_scanned,
    files_total, files_processed, files_skipped, files_error,
    new_messages, new_turns, new_issues, new_skill_calls
) VALUES (
    #{triggerType}, #{status}, #{startedAt}, #{usersScanned}, #{dirsScanned},
    #{filesTotal}, #{filesProcessed}, #{filesSkipped}, #{filesError},
    #{newMessages}, #{newTurns}, #{newIssues}, #{newSkillCalls}
