UPDATE dashboard_scan_history
SET status = #{status}, 
    finished_at = NOW(), 
    duration_ms = #{durationMs}

    , error_message = #{errorMessage}


    , users_scanned = #{usersScanned}


    , dirs_scanned = #{dirsScanned}


    , files_total = #{filesTotal}


    , files_processed = #{filesProcessed}


    , files_skipped = #{filesSkipped}


    , files_error = #{filesError}


    , new_messages = #{newMessages}


    , new_turns = #{newTurns}


    , new_issues = #{newIssues}


    , new_skill_calls = #{newSkillCalls}

WHERE id = #{id}

UPDATE dashboard_scan_history
SET agg_hours_from_files = #{aggHoursFromFiles},
    agg_hours_from_window = #{aggHoursFromWindow},
    agg_hours_total = #{aggHoursTotal},
    agg_duration_ms = #{aggDurationMs}
WHERE id = #{id}

UPDATE dashboard_scan_history
SET status = #{status},
    error_message = #{errorMessage}
WHERE id = #{id}
